// Auto-generated base64 mask data for file:// compatibility
const MASK_DATA = {};
MASK_DATA["assets/circles/masks/circle-1.png"] = "data:image/png;base64,";
MASK_DATA["assets/circles/masks/circle-2.png"] = "data:image/png;base64,";
MASK_DATA["assets/circles/masks/circle-3.png"] = "data:image/png;base64,";
MASK_DATA["assets/circles/masks/circle-4.png"] = "data:image/png;base64,";
MASK_DATA["assets/circles/masks/circle-5.png"] = "data:image/png;base64,";
MASK_DATA["assets/underlines/underline-1.png"] = "data:image/png;base64,";
MASK_DATA["assets/underlines/underline-2.png"] = "data:image/png;base64,";
MASK_DATA["assets/underlines/underline-3.png"] = "data:image/png;base64,";

// Apply masks to all elements with data-mask attribute
function applyMasks() {
  document.querySelectorAll('[data-mask]').forEach(el => {
    const maskPath = el.getAttribute('data-mask');
    const dataUri = MASK_DATA[maskPath];
    if (dataUri) {
      el.style.webkitMaskImage = 'url(' + dataUri + ')';
      el.style.maskImage = 'url(' + dataUri + ')';
    }
  });
}
document.addEventListener('DOMContentLoaded', applyMasks);
